// editorial_eyeを300字以内に収める
function truncateEye(text, maxLen) {
  if (!text || text.length <= maxLen) return text;
  const cut = text.substring(0, maxLen);
  const lastPeriod = Math.max(cut.lastIndexOf('。'), cut.lastIndexOf('．'));
  return lastPeriod > maxLen * 0.6 ? cut.substring(0, lastPeriod + 1) : cut;
}

const aggregated = $input.first().json;
const news = Array.isArray(aggregated.data) ? aggregated.data : 
             Array.isArray(aggregated) ? aggregated : [];

// outputフィールドのJSONをパースするヘルパー
function parseNewsItem(n) {
  if (n.japanese_headline) return n; // すでに展開済み
  let raw_str = '';
  // Gemini API HTTP Response形式
  if (n.candidates && n.candidates[0]) {
    raw_str = (n.candidates[0].content && n.candidates[0].content.parts && n.candidates[0].content.parts[0]) 
              ? n.candidates[0].content.parts[0].text || '' : '';
  }
  // chainLlm / agent 出力形式
  if (!raw_str) raw_str = n.text || n.output || '';
  if (raw_str) {
    try {
      const raw = raw_str.replace(/^```json\s*/,'').replace(/\s*```$/,'').trim();
      return JSON.parse(raw);
    } catch(e) { return {}; }
  }
  return n;
}

let body = '';
for (let i = 0; i < news.length; i++) {
  const n = parseNewsItem(news[i]);
  const pubDate = n.pubDate || n.pub_date || '';
  const dateStr = pubDate ? new Date(pubDate).toLocaleDateString('ja-JP', {year:'numeric',month:'long',day:'numeric'}) : '';

  body += `### ◆ ${n.japanese_headline || ''}\n\n`;
  body += `**配信日：** ${dateStr}　**出典：** ${n.source_media || ''}　**原題：** ${n.original_title || ''}\n\n`;
  body += `${n.fact_summary || ''}\n\n`;
  body += `**📌 編集長の眼**\n\n${truncateEye(n.editorial_eye || '', 300)}\n\n`;
  body += `---\n\n`;
}

return [{ json: { news_body: body, news_count: news.length, news_data: news } }];

