function extractGeminiText(resp) {
  if (!resp) return '';
  if (resp.candidates && resp.candidates[0] && resp.candidates[0].content && resp.candidates[0].content.parts) {
    return resp.candidates[0].content.parts[0].text || '';
  }
  return resp.text || '';
}

const leadResp = $('リード＋総括 LLM Chain').first().json;
const titleResp = $('タイトル生成 LLM Chain').first().json;

const leadRawStr = extractGeminiText(leadResp);
const titleText = extractGeminiText(titleResp).trim().replace(/^["「]|["」]$/g, '').split('\n')[0].trim();

let leadJson;
try {
  const cleaned = leadRawStr.replace(/^```json\s*/,'').replace(/\s*```$/,'').trim();
  leadJson = JSON.parse(cleaned);
} catch(e) { leadJson = {lead:'', closing:''}; }


// closingを1400字以内に収める（文章境界で切る）
function truncateAtSentence(text, maxLen) {
  if (!text || text.length <= maxLen) return text;
  const cut = text.substring(0, maxLen);
  const lastPeriod = Math.max(cut.lastIndexOf('。'), cut.lastIndexOf('．'), cut.lastIndexOf('\n\n'));
  return lastPeriod > maxLen * 0.5 ? cut.substring(0, lastPeriod + 1) : cut;
}
const lead = leadJson.lead || '';
const closing = truncateAtSentence(leadJson.closing || '', 1400);
const newsBody = $('記事本文組立Code').first().json.news_body || '';
const newsData = $('記事本文組立Code').first().json.news_data || [];

const nl = '\n';
const finalArticle = [
  '# ' + titleText,
  '',
  lead,
  '',
  newsBody,
  '## ◆ 総括：時代の濁流を読み解く',
  '',
  closing,
  ''
].join(nl);

const now = new Date();
const dateStr = String(now.getFullYear())
  + String(now.getMonth()+1).padStart(2,'0')
  + String(now.getDate()).padStart(2,'0')
  + '-'
  + String(now.getHours()).padStart(2,'0')
  + String(now.getMinutes()).padStart(2,'0')
  + String(now.getSeconds()).padStart(2,'0');

return [{
  json: {
    final_article: finalArticle,
    final_title: titleText,
    lead_text: lead,
    closing_text: closing,
    news_data: newsData,
    slug: dateStr,
    publishDate: now.toISOString()
  }
}];

const data = $input.first().json;
const title = data.final_title || '';
const newsData = data.news_data || [];

const styleBase = 'Moebius comic style, ligne claire, detailed crosshatching, muted earth tones, cinematic composition, dramatic lighting, ultra detailed';

const prompts = [];

prompts.push({ type: 'cover', prompt: `${styleBase}, futuristic technology landscape, AI neural network visualization, global network, professional editorial illustration, ${title}` });

const compositions = ['wide establishing shot', 'close-up detail shot', 'birds eye view', 'dramatic low angle'];
const lighting = ['dark moody', 'bright daylight', 'neon glow', 'golden hour'];

for (let i = 0; i < Math.min(newsData.length, 4); i++) {
  const keywords = (newsData[i].japanese_headline || '').substring(0, 30);
  prompts.push({
    type: `news_${i}`,
    prompt: `${styleBase}, ${compositions[i]}, ${lighting[i]}, technology concept, ${keywords}, editorial illustration`
  });
}

prompts.push({ type: 'closing', prompt: `${styleBase}, panoramic cityscape, people and technology harmonizing, hopeful future, wide shot, blue tones` });

return prompts.map(p => ({ json: p }));

const items = $input.all();
const urls = {};
for (const item of items) {
  const type = item.json.type || 'unknown';
  const url = item.json.secure_url || item.json.url || '';
  if (url) urls[type] = url;
}
return [{ json: { image_urls: urls } }];

const imageData = $input.first().json;
const articleData = $("最終組立Code").first().json;
let article = articleData.final_article || '';
const urls = imageData.image_urls || {};

if (urls.cover) {
  article = article.replace(/^(# .+\n\n)/, `$1![表紙](${urls.cover})\n\n`);
}

for (let i = 0; i < 4; i++) {
  const newsUrl = urls['news_' + i];
  if (newsUrl) {
    const regex = new RegExp('(### 【ニュース：[^\\n]+】\\n\\n)(\\*\\*配信日)');
    article = article.replace(regex, '$1![ニュース画像](' + newsUrl + ')\n\n$2');
  }
}

if (urls.closing) {
  article = article.replace(
    /(## 【クロージング総括[^\n]*】\n)/,
    `$1\n![総括画像](${urls.closing})\n`
  );
}

return [{ json: { ...articleData, final_article: article, image_urls: urls } }];

const data = $input.first().json;
